#!/usr/bin/env bash
set -euo pipefail

BASE_DIR="$(cd "$(dirname "$0")" && pwd)"
RUNTIME_DIR="$BASE_DIR/runtime"
PROFILE_ENV_FILE="${OBSERVABILITY_PROFILE_ENV_FILE:-$RUNTIME_DIR/observability.env}"
SEATUNNELX_BASE_URL="${1:-${SEATUNNELX_BASE_URL:-http://127.0.0.1:8000}}"
SEATUNNELX_BASE_URL="${SEATUNNELX_BASE_URL%/}"

mkdir -p "$RUNTIME_DIR"

cat > "$PROFILE_ENV_FILE" <<ENV
# Generated by deps/set-observability-remote-mode.sh
# Remote integration profile for deps observability stack
PROMETHEUS_USE_HTTP_SD=true
PROMETHEUS_HTTP_SD_URL=${SEATUNNELX_BASE_URL}/api/v1/monitoring/prometheus/discovery
PROMETHEUS_HTTP_SD_REFRESH_INTERVAL=30s
ALERTMANAGER_WEBHOOK_URL=${SEATUNNELX_BASE_URL}/api/v1/monitoring/alertmanager/webhook
ENV

echo "wrote profile: $PROFILE_ENV_FILE"

set -a
# shellcheck disable=SC1090
source "$PROFILE_ENV_FILE"
set +a

"$BASE_DIR/init-observability-defaults.sh"
echo "regenerated runtime configs in remote mode"

# best-effort hot reload for running services
if curl -sS -m 2 -o /dev/null -w '%{http_code}' -X POST http://127.0.0.1:9090/-/reload | grep -q '^200$'; then
  echo "prometheus reloaded"
else
  echo "prometheus reload skipped (service may not be running)"
fi

am_pid=""
if [[ -f "$RUNTIME_DIR/alertmanager/alertmanager.pid" ]]; then
  am_pid="$(cat "$RUNTIME_DIR/alertmanager/alertmanager.pid" 2>/dev/null || true)"
fi
if [[ -z "$am_pid" ]]; then
  am_pid="$(pgrep -f '/deps/alertmanager/alertmanager' | head -n1 || true)"
fi
if [[ -n "$am_pid" ]] && kill -0 "$am_pid" 2>/dev/null; then
  kill -HUP "$am_pid"
  echo "alertmanager reloaded by SIGHUP (pid=$am_pid)"
else
  echo "alertmanager reload skipped (service may not be running)"
fi

echo "remote mode applied. next 'deps/start-observability.sh' will keep this profile by default."
